package github.chains;

import javax.xml.parsers.DocumentBuilder;
import javax.xml.parsers.DocumentBuilderFactory;
import javax.xml.transform.OutputKeys;
import javax.xml.transform.Transformer;
import javax.xml.transform.TransformerFactory;
import javax.xml.transform.dom.DOMSource;
import javax.xml.transform.stream.StreamResult;
import org.w3c.dom.Document;
import org.w3c.dom.Element;
import org.w3c.dom.NodeList;
import java.io.File;
import java.io.IOException;
import java.util.Arrays;
import java.util.List;
import javax.xml.parsers.ParserConfigurationException;
import javax.xml.transform.TransformerException;
import org.xml.sax.SAXException;

public class Main {

    private static final String NEW_SOURCE_VERSION = "1.7";
    private static final String NEW_TARGET_VERSION = "1.7";

    public static void main(String[] args) throws Exception {
        if (args.length < 1) {
            System.err.println("Usage: java github.chains.Main <jadler-project-root>");
            System.exit(1);
        }

        String jadlerRoot = args[0];
        List<String> pomFiles = Arrays.asList(
            jadlerRoot + "/pom.xml",
            jadlerRoot + "/jadler-core/pom.xml",
            jadlerRoot + "/jadler-jetty/pom.xml",
            jadlerRoot + "/jadler-junit/pom.xml",
            jadlerRoot + "/jadler-jdk/pom.xml",
            jadlerRoot + "/jadler-all/pom.xml"
        );

        int fixedCount = 0;
        for (String pomPath : pomFiles) {
            File pomFile = new File(pomPath);
            if (pomFile.exists()) {
                if (fixPomFile(pomFile)) {
                    System.out.println("Fixed: " + pomPath);
                    fixedCount++;
                } else {
                    System.out.println("No changes needed: " + pomPath);
                }
            } else {
                System.out.println("Not found: " + pomPath);
            }
        }

        System.out.println("Transformation complete. Fixed " + fixedCount + " file(s).");
    }

    private static boolean fixPomFile(File pomFile) throws ParserConfigurationException, SAXException, IOException, TransformerException {
        DocumentBuilderFactory factory = DocumentBuilderFactory.newInstance();
        factory.setNamespaceAware(true);
        DocumentBuilder builder = factory.newDocumentBuilder();
        Document doc = builder.parse(pomFile);

        boolean changed = false;

        NodeList sourceNodes = doc.getElementsByTagName("source");
        for (int i = 0; i < sourceNodes.getLength(); i++) {
            Element sourceElement = (Element) sourceNodes.item(i);
            if (sourceElement.getTextContent().trim().equals("1.6")) {
                sourceElement.setTextContent(NEW_SOURCE_VERSION);
                changed = true;
            }
        }

        NodeList targetNodes = doc.getElementsByTagName("target");
        for (int i = 0; i < targetNodes.getLength(); i++) {
            Element targetElement = (Element) targetNodes.item(i);
            if (targetElement.getTextContent().trim().equals("1.6")) {
                targetElement.setTextContent(NEW_TARGET_VERSION);
                changed = true;
            }
        }

        if (changed) {
            TransformerFactory transformerFactory = TransformerFactory.newInstance();
            Transformer transformer = transformerFactory.newTransformer();
            transformer.setOutputProperty(OutputKeys.INDENT, "yes");
            transformer.setOutputProperty("{http://xml.apache.org/xslt}indent-amount", "4");
            DOMSource source = new DOMSource(doc);
            StreamResult result = new StreamResult(pomFile);
            transformer.transform(source, result);
        }

        return changed;
    }
}

